import { Button, Stack } from "@mui/material";

import { DataTable } from "@/components/ui/data-table";
import { formatCurrencyEur, formatStatusLabel } from "@/lib/formatters";
import { Expense } from "@/services/types";

export function ExpenseList({
  expenses,
  onEdit,
  onDelete
}: {
  expenses: Expense[];
  onEdit: (expense: Expense) => void;
  onDelete: (expense: Expense) => void;
}) {
  return (
    <DataTable
      rows={expenses}
      columns={[
        { key: "title", header: "Title", render: (expense) => expense.title },
        { key: "status", header: "Status", render: (expense) => formatStatusLabel(expense.status) },
        {
          key: "amount",
          header: "Amount",
          render: (expense) => formatCurrencyEur(expense.amount)
        },
        {
          key: "actions",
          header: "Actions",
          render: (expense) => (
            <Stack direction="row" spacing={1}>
              <Button size="small" variant="outlined" onClick={() => onEdit(expense)}>
                Edit
              </Button>
              <Button size="small" variant="contained" color="error" onClick={() => onDelete(expense)}>
                Delete
              </Button>
            </Stack>
          )
        }
      ]}
    />
  );
}
